  ('fire-eq-tech-moex-02440', 'fire-eq-tech', 'fire-eq-tech-moex-101-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '受信總機竣工後試驗二信號式機能，測試其火災表示，依規定操作火警表示試驗開關，就各回路進行， 下列步驟何者為錯誤？', '["第一信號時，地區表示裝置應亮燈及主音響裝置應鳴動", "第二信號時，火警燈應即亮燈、地區表示裝置亮燈及主、地區音響裝置應鳴動", "使發信機動作應在接收第二信號時操作", "使發信機動作時火警及地區表示亮燈、主音響及地區音響裝置鳴動"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:24+00:00", "source_pdf_sha1": "8e5e11bd90b0", "answer_pdf_sha1": "0cd233c386e9", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "902", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
